<section class="auth-shell shell"><div class="auth-card card"><div class="auth-heading"><span class="maintenance-clock" aria-hidden="true">✓</span><p class="eyebrow">Sensitive action</p><h1 class="heading-auth">Confirm it’s you</h1><p class="muted">Re-enter your password<?= !empty($user['two_factor_enabled']) ? ' and second factor' : '' ?> to begin a short-lived privileged session.</p></div><form class="form-stack" method="post" action="<?= $url('auth.confirm-password.store', [], '/confirm-password') ?>"><?= function_exists('csrf_field')?csrf_field():'' ?><input type="hidden" name="intent" value="<?= $esc((string)($data['intent']??'')) ?>"><label class="field"><span>Current password</span><input type="password" name="password" autocomplete="current-password" required autofocus></label><?php if(!empty($user['two_factor_enabled'])): ?><label class="field"><span>Authenticator or recovery code</span><input name="two_factor_code" autocomplete="one-time-code" inputmode="text" maxlength="64" required><small>Use the six-digit authenticator code or one unused recovery code.</small></label><?php endif; ?><button class="button button-gold button-wide">Continue securely</button></form></div></section>
